#include <bits/stdc++.h>
#define int long long
using namespace std;
struct Edge {
	int L , R , sum , flag;
}; 
Edge tr[400005];
int a[400005];
int n , m;
void pushup( Edge &tM , Edge &tL , Edge &tR ) {
	tM.flag = tL.flag & tR.flag;
	tM.sum = tL.sum + tR.sum;
}
void build( int p , int L , int R ) {
	tr[p].L = L , tr[p].R = R;
	if( L == R ) {
		tr[p].sum = a[L];
		tr[p].flag = ( a[L] == 1 );
		return;
	}
	int mid = ( L + R ) / 2;
	build( p << 1 , L , mid );
	build( ( p << 1 ) + 1 , mid + 1 , R );
	pushup( tr[p] , tr[p << 1] , tr[p << 1 | 1] );
}
void modify( int p , int l , int r ) {
	if( tr[p].L > r || tr[p].R < l ) {
		return;
	}
	if( tr[p].L == tr[p].R ) {
		a[tr[p].L] = floor( sqrt( a[tr[p].L] ) );
		tr[p].sum = a[tr[p].L];
		tr[p].flag = ( a[tr[p].L] <= 1 );
		return;
	}
	if( tr[p].flag ) {
		return;
	}
	modify( p << 1 , l , r );
	modify( p << 1 | 1 , l , r );
	pushup( tr[p] , tr[p << 1] , tr[p << 1 | 1] );
}
int query( int p , int a , int b ) {
	if( tr[p].L > b || tr[p].R < a ) {
		return 0;
	}
	if( tr[p].L >= a && tr[p].R <= b ) {
		return tr[p].sum;
	}
	int sum = 0;
	sum += query( p << 1 , a , b );
	sum += query( ( p << 1 ) + 1 , a , b );
	return sum;
}
signed main() {
	cin >> n;
	for( int i = 1 ; i <= n ; i++ ) {
		cin >> a[i];
	}
	cin >> m;
	build( 1 , 1 , n );
	while( m-- ) {
		int op , l , r;
		cin >> op >> l >> r;
		if( l > r ) {
			swap( l , r );
		}
		if( op == 0 ) {
			modify( 1 , l , r );
		} else {
			cout << query( 1 , l , r ) << '\n';
		}
	}
	return 0;
}
